<?php
 namespace League\CommonMark; use League\CommonMark\Block\Element\AbstractBlock; use League\CommonMark\Block\Element\Document; use League\CommonMark\Reference\ReferenceParser; class Context implements ContextInterface { protected $environment; protected $doc; protected $tip; protected $container; protected $lineNumber; protected $line; protected $blockCloser; protected $blocksParsed = false; protected $referenceParser; public function __construct(Document $document, EnvironmentInterface $environment) { $this->doc = $document; $this->tip = $this->doc; $this->container = $this->doc; $this->environment = $environment; $this->referenceParser = new ReferenceParser($document->getReferenceMap()); $this->blockCloser = new UnmatchedBlockCloser($this); } public function setNextLine(string $line) { ++$this->lineNumber; $this->line = $line; } public function getDocument(): Document { return $this->doc; } public function getTip(): ?AbstractBlock { return $this->tip; } public function setTip(?AbstractBlock $block) { $this->tip = $block; return $this; } public function getLineNumber(): int { return $this->lineNumber; } public function getLine(): string { return $this->line; } public function getBlockCloser(): UnmatchedBlockCloser { return $this->blockCloser; } public function getContainer(): AbstractBlock { return $this->container; } public function setContainer(AbstractBlock $container) { $this->container = $container; return $this; } public function addBlock(AbstractBlock $block) { $this->blockCloser->closeUnmatchedBlocks(); $block->setStartLine($this->lineNumber); while ($this->tip !== null && !$this->tip->canContain($block)) { $this->tip->finalize($this, $this->lineNumber); } if ($this->tip !== null) { $this->tip->appendChild($block); } $this->tip = $block; $this->container = $block; } public function replaceContainerBlock(AbstractBlock $replacement) { $this->blockCloser->closeUnmatchedBlocks(); $replacement->setStartLine($this->container->getStartLine()); $this->container->replaceWith($replacement); if ($this->tip === $this->container) { $this->tip = $replacement; } $this->container = $replacement; } public function getBlocksParsed(): bool { return $this->blocksParsed; } public function setBlocksParsed(bool $bool) { $this->blocksParsed = $bool; return $this; } public function getReferenceParser(): ReferenceParser { return $this->referenceParser; } } 